/*
 * Filters a patient dataset to only include those with abnormal lab results
 * and creates a new variable for follow-up flag
*/

/* Create a new dataset with only the necessary variables */
data patient_abnormal_labs (keep=patient_id date_labs lab_type lab_value follow_up_flag);
    set raw_patient_data;

    /* Define the length and format for the follow-up flag */
    length follow_up_flag $10;
    format date_labs date9.;

    /* Check if the lab value is abnormal */
    if lab_type = 'GLU' and lab_value > 125 then do;
        follow_up_flag = 'Urgent';
    end;
    else if lab_type = 'CREATININE' and lab_value > 1.3 then do;
        follow_up_flag = 'High';
    end;
    else if lab_type = 'HDL' and lab_value < 40 then do;
        follow_up_flag = 'Low';
    end;
    else do;
        follow_up_flag = 'Normal';
        /* Drop observations with normal lab values */
        drop _all_;
    end;

    /* Assign a patient ID if it doesn't exist */
    if missing(patient_id) then do;
        patient_id = 999999;
    end;

    /* Label the follow-up flag variable */
    label follow_up_flag = 'Follow-Up Priority';

    /* Filter the data to include only the necessary observations */
    where not missing(date_labs);
run;

data work.patient_visits_clean;
  set raw.patient_visits;

  /* Set lengths for new variables */
  length visit_category $ 20 visit_duration_hrs 8 Sharma_Score 8;

  /* Drop unnecessary variables */
  drop admission_time temp_bp temp_heart_rate;

  /* Assignment statements */
  visit_category = 'Unknown';
  visit_duration_hrs = (discharge_time - admission_time) / 3600;
  Sharma_Score = (systolic_bp * 0.4) + (blood_sugar * 0.3) + (age * 0.15) + (bmi * 0.15);

  /* Format application */
  format admission_time discharge_time datetime20.;
  format Sharma_Score 8.2 visit_duration_hrs 10.2;

  /* Conditional logic */
  if missing(blood_sugar) or missing(systolic_bp) then do;
    visit_category = 'Incomplete Records';
    Sharma_Score = .;
  end;
  else if visit_duration_hrs > 12 then visit_category = 'Long Stay Visit';
  else if visit_duration_hrs > 4 then visit_category = 'Standard Visit';
  else do;
    visit_category = 'Short Stay Visit';
    Sharma_Score = Sharma_Score * 0.8;
  end;

  /* Keep only necessary variables */
  keep patient_id admission_time discharge_time visit_duration_hrs
      Sharma_Score visit_category diagonosis_code;

  /* Conditionally exclude some records */
  if Sharma_Score < 10 or diagnostic_code = ' ' then delete;

  /* Data quality check */
  if visit_duration_hrs < 0 then do;
    put "WARNING: Negative duration for patient " patient_id;
    visit_duration_hrs = .;
  end;

  /* Labels */
  label visit_category = "Category based on visit duration and completeness"
        Sharma_Score = "Composite health metric developed for NDASH"
        visit_duration_hrs = "Visit duration in hours";

  /* Categorize by Sharma_Score */
  if Sharma_Score < 30 then risk_level = 'Low';
  else if Sharma_Score < 70 then risk_level = 'Medium';
  else do;
    risk_level = 'High';
    if visit_category ne 'Long Stay Visit' then
      put "ALERT: High Sharma Score but not long visit for patient " patient_id;
  end;

  format risk_level $RiskLevelFmt.;
run;

