  /* MERGE_SEMANTICS: SAS will match the records based on the BY value */
run;

/* One-to-Many Merge */
data merged_dataset_1tom;
  merge customers (in=in_cust) orders;
  by customer_id;

  /* Only include observations where the customer exists */
  if in_cust;

  /* Create a new variable to indicate the source of the data */
  data_source = 'One-to-Many Merge';

  /* MERGE_SEMANTICS: SAS will replicate the customer record for each matching order record */
run;

/* Update existing records */
