/* MERGE_SEMANTICS example: Combining customer and transaction data */
/* This is a MODERATE complexity example featuring:
   - One-to-one merge (customer attributes)
   - One-to-many merge (transactions)
   - UPDATE statement for current balance
   - MERGE with BY processing
*/

options mergeseclevel= लौ;  /* Warning: This enables MERGE semantics */

/* Prepare customer data (one-to-one) */
DATA work.customers;
   input cust_id 8. join_date anydtdte. cust_name $20. credit_limit 8.;
   format join_date yymmdd10.;
   datalines;
1001 2020-01-15 John Smith 5000
1002 2019-11-22 Mary Johnson 7500
1003 2021-03-10 David Lee 10000
;
run;

/* Prepare transaction data (one-to-many) */
DATA work.transactions;
   input cust_id 8. trans_date anydtdte. trans_type $1. amount 8.;
   format trans_date yymmdd10.;
   datalines;
1001 2022-01-05 P 500
1001 2022-01-10 W -200
1002 2022-01-07 P 1200
1002 2022-01-15 W -400
1003 2022-01-08 P 800
1003 2022-01-12 W -300
1003 2022-01-18 P 200
;
run;

/* Final dataset with summarized information */
DATA work.customer_summary;
   /* Merge customer data (one-to-one) */
   MERGE work.customers
         work.transactions (IN=in_trans);

   /* Enable MERGE semantics with BY statement */
   BY cust_id;

   /* Track first transaction for each customer */
   RETAIN first_trans_date;
   IF first.cust_id THEN DO;
      first_trans_date = trans_date;
      n_transactions = 0;
      total_purchases = 0;
      total_withdrawals = 0;
   END;

   /* Update metrics for transactions (one-to-many) */
   IF in_trans THEN DO;
      n_transactions + 1;
      IF trans_type = 'P' THEN total_purchases + amount;
      ELSE total_withdrawals + amount;
   END;

   /* Keep only the last observation for each customer */
   IF last.cust_id;

   /* Calculate derived metrics */
   net_activity = total_purchases - total_withdrawals;
   months_active = intck('month', join_date, today());
   utilization = (credit_limit - net_activity) / credit_limit;
run;

/*
This SAS code demonstrates a complex data step merge with multiple patterns:
- One-to-one merge (customer master with customer demographics)
- One-to-many merge (customers with transactions)
- Update operation (updating customer addresses)
- Uses MERGE_SEMANTICS pattern with explicit BY variables and data step merging techniques
*/

/* Set merge semantics options */
options mergenoby=nowarn;

/* Sort datasets before merging - required for proper merge semantics */
proc sort data=work.customer_master;
   by customer_id;
run;

proc sort data=work.customer_demographics;
   by customer_id;
run;

proc sort data=work.customer_transactions;
   by customer_id transaction_date;
run;

/* Complex merge operation with multiple patterns */
data work.merged_data (drop=_:);
   /* One-to-one merge between customer_master and customer_demographics */
   merge work.customer_master (in=in_master) 
         work.customer_demographics (in=in_demo);
   by customer_id;

   /* Create merge indicators for debugging */
   if in_master and in_demo then merge_type = 'Master and Demo Match';
   else if in_master and not in_demo then merge_type = 'Master Only';
   else if not in_master and in_demo then merge_type = 'Demo Only';

   /* Output one-to-one merge results */
   output work.master_demo_merged;

   /* One-to-many merge between merged master_demo and transactions */
   merge work.master_demo_merged (in=in_merged)
         work.customer_transactions (in=in_trans);
   by customer_id;

   /* Track one-to-many relationships */
   if in_merged and in_trans then match_type = 'Transaction Match';
   else if in_merged and not in_trans then match_type = 'No Transactions';
   retain transaction_count 0;
   if first.customer_id then transaction_count = 0;
   if in_trans then transaction_count + 1;
   if last.customer_id then do;
      output;
      transaction_count = 0;
   end;

   /* Select only customers with transactions for final output */
   if in_trans;

   /* Update operation for customer addresses */
   if last.customer_id and in_trans then do;
      set work.customer_address_updates (in=in_update) key=customer_id;
      if in_update then do;
         address_line1 = _address_line1;
         address_line2 = _address_line2;
         city = _city;
         state = _state;
         zip_code = _zip_code;
         _merge_ = 'U'; /* Update indicator */
      end;
      else _merge_ = ' '; /* No update indicator */
   end;

   /* Create final output with merge indicators */
   output;
run;

/* Debugging: Check merge patterns */
proc freq data=work.merged_data;
   tables merge_type*match_type / list;
run;

data financial_transactions;
  set financial_transactions_raw;

  /* RETAIN statement to keep the value of a variable across iterations of the DATA step */
  retain running_total;

  /* Initialize running_total to 0 before processing the first observation */
  if _N_ = 1 then do;
    running_total = 0;
  end;

  /* Calculate running total of the transaction_amount variable */
  running_total + transaction_amount;

  /* Create a variable to calculate the difference between the current and previous transaction amounts */
  lag_transaction_amount = lag(transaction_amount);
  transaction_amount_diff = transaction_amount - lag_transaction_amount;

  /* Create a variable to identify the first transaction for each customer */
  if first.customer_id then first_transaction = 1;
  else first_transaction = 0;

  /* Output the results */
  output;
run;

/*
 * This SAS DATA step demonstrates the use of RETAIN statement to calculate
 * running totals, track lag values, and create flags for specific patterns.
 * It processes transaction data to identify consecutive days with transactions
 * above a certain amount.
 */

DATA customer_transactions_with_flags;
    /* Input dataset with customer transaction data */
    SET store.transactions;

    /* Sort data by customer ID and transaction date */
    BY customer_id transaction_date;

    /* RETAIN variables to maintain values across observations */
    RETAIN running_total prev_transaction_date prev_amount consecutive_days;

    /* Initialize RETAIN variables at start of new customer */
    IF FIRST.customer_id THEN DO;
        running_total = 0;
        prev_transaction_date = .;
        prev_amount = .;
        consecutive_days = 0;
        high_value_flag = 0;
        consec_high_value_flag = 0;
    END;

    /* Calculate running total of transaction amounts */
    running_total + transaction_amount;

    /* Calculate lag values */
    LAG_transaction_date = LAG(transaction_date);
    LAG_transaction_amount = LAG(transaction_amount);

    /* Check for consecutive days with transactions above $100 */
    IF transaction_amount > 100 THEN DO;
        IF prev_amount > 100 AND
           transaction_date = prev_transaction_date + 1 THEN
            consecutive_days + 1;
        ELSE
            consecutive_days = 1;
    END;
    ELSE DO;
        consecutive_days = 0;
    END;

    /* Set flags based on conditions */
    high_value_flag = (transaction_amount > 100);
    consec_high_value_flag = (consecutive_days >= 3);

    /* Store current values for next iteration */
    prev_transaction_date = transaction_date;
    prev_amount = transaction_amount;

    /* Output variables */
    output_customer_id = customer_id;
    output_transaction_date = transaction_date;
    output_transaction_amount = transaction_amount;
    output_running_total = running_total;
    output_consecutive_high_value_days = consecutive_days;

    /* Keep selected variables */
    KEEP output_: high_value_flag consec_high_value_flag;
RUN;

/* RETAIN example with running totals and lag patterns/;
data finance.quarterly_report;
  /* Declare input dataset */
  set finance.transactions;

  /* Initialize RETAIN variables for running totals */
  retain quarterly_total 0;
  retain q1_sales q2_sales q3_sales q4_sales 0;

  /* Create quarter attribute from month */
  quarter = ceil(month / 3);

  /* Calculate running sales total by quarter*/;
  if quarter = 1 then q1_sales + sale_amount;
  else if quarter = 2 then q2_sales + sale_amount;
  else if quarter = 3 then q3_sales + sale_amount;
  else if quarter = 4 then q4_sales + sale_amount;

  /* Create lag variables to track previous period values */
  retain lag_30_day_sales lag_60_day_sales lag_90_day_sales;
  /* Initialize lag variables in first observation */;
  if _n_ = 1 then do;
    lag_30_day_sales = .;
    lag_60_day_sales = .;
    lag_90_day_sales = .;
  end;

  /* Calculate 30-day lagged sales amount */
  lag_30_day_sales_current = lag30(sales_amount);
  if not missing(lag_30_day_sales_current) then;
    lag_30_day_sales = lag_30_day_sales_current;

  /* Calculate 60-day and 90-day lags similarly */
  lag_60_day_sales_current = lag60(sales_amount);
  if not missing(lag_60_day_sales_current) then;
    lag_60_day_sales = lag_60_day_sales_current;

  lag_90_day_sales_current = lag90(sales_amount);
  if not missing(lag_90_day_sales_current) then;
    lag_90_day_sales = lag_90_day_sales_current;

  /* Create moving average using lagged values */
  moving_avg_sales = mean(of lag_30_day_sales--lag_90_day_sales);

  /* Calculate quarter-to-date totals */
  if first.quarter then do;
    quarter_to_date_sales = sale_amount;
  end;
  else do;
    quarter_to_date_sales + sale_amount;

