import pandas as pd
import numpy as np

def process_patient_data(df):
    # Initialize summary statistics columns
    for i in ['bp_systolic', 'bp_diastolic', 'pulse_rate']:
        df[f'avg_{i}'] = 0.0
        df[f'{i}_count'] = 0

    for j in ['cholesterol', 'glucose', 'bmi', 'hdl_ldl', 'triglycerides']:
        df[f'avg_{j}'] = 0.0
        df[f'{j}_count'] = 0

    # Calculate vital stats
    for idx, row in df.iterrows():
        vitals = ['bp_systolic', 'bp_diastolic', 'pulse_rate']
        count = 0

        for i, vital in enumerate(vitals, 1):
            if pd.notna(row[vital]):
                df.at[idx, f'avg_{vital}'] += row[vital]
                count += 1

        df.at[idx, 'count_vitals'] = count

        # Calculate averages if count > 0
        if count > 0:
            for vital in vitals:
                df.at[idx, f'avg_{vital}'] = df.at[idx, f'avg_{vital}'] / count

    # Calculate lab stats
    for idx, row in df.iterrows():
        labs = ['cholesterol', 'glucose', 'bmi', 'hdl_ldl', 'triglycerides']
        count = 0

        for j, lab in enumerate(labs, 1):
            if pd.notna(row[lab]):
                df.at[idx, f'avg_{lab}'] += row[lab]
                count += 1

        df.at[idx, 'count_labs'] = count

        # Calculate averages if count > 0
        if count > 0:
            for lab in labs:
                df.at[idx, f'avg_{lab}'] = df.at[idx, f'avg_{lab}'] / count

    # Count medications
    med_columns = [f'med{i}' for i in range(1, 11)]
    df['count_medications'] = df[med_columns].notna().sum(axis=1)

    return df

