/* Program Name: Patient Data Analysis */
/* Created By:  John Doe */
/* Created On:  31JUL2023  */
/* Purpose:     Analyze patient data for multiple time points */

/* Import raw data from CSV */
DATA PatientData;
    INFILE 'patient_data_raw.csv' DLM=',' DSD FIRSTOBS=2;
    INPUT PatientID Gender $ Age Weight TimePoint1_Glucose TimePoint2_Glucose
          TimePoint1_BloodPressure.TimePoint2_BloodPressure
          TimePoint1_Cholestorol TimePoint2_Cholestorol;
RUN;

/* Create arrays for multi-timepoint variables */
DATA PatientAnalysis;
    SET PatientData;

    /* Define arrays for Glucose, Blood Pressure, and Cholestorol */
    ARRAY Glucose{2} TimePoint1_Glucose TimePoint2_Glucose;
    ARRAY BloodPressure{2} TimePoint1_BloodPressure TimePoint2_BloodPressure;
    ARRAY Cholestorol{2} TimePoint1_Cholestorol TimePoint2_Cholestorol;

    /* Calculate changes between time points */
    ARRAY Changes{3,2} _TEMPORARY_ (0,0. 0,0. 0,0); /* 3 variables x 2 changes */
    DO i = 1 TO 2;
        Changes{1,i} = Glucose{i+1} - Glucose{i};
        Changes{2,i} = BloodPressure{i+1} - BloodPressure{i};
        Changes{3,i} = Cholestorol{i+1} - Cholestorol{i};
    END;

    /* Calculate average changes */
    AvgGlucoseChange = MEAN(of Changes{1,});
    AvgBloodPressureChange = MEAN(of Changes{2,});
    AvgCholestorolChange = MEAN(of Changes{3,});

    /* Categorize patients based on changes */
    IF AvgGlucoseChange > 0 THEN GlucoseTrend = 'Increasing';
    ELSE IF AvgGlucoseChange < 0 THEN GlucoseTrend = 'Decreasing';
    ELSE GlucoseTrend = 'Stable';

    IF AvgBloodPressureChange > 0 THEN BloodPressureTrend = 'Increasing';
    ELSE IF AvgBloodPressureChange < 0 THEN BloodPressureTrend = 'Decreasing';
    ELSE BloodPressureTrend = 'Stable';

    IF AvgCholestorolChange > 0 THEN CholestorolTrend = 'Increasing';
    ELSE IF AvgCholestorolChange < 0 THEN CholestorolTrend = 'Decreasing';
    ELSE CholestorolTrend = 'Stable';

    /* Output results */
    DROP i;
    KEEP PatientID Gender Age Weight AvgGlucoseChange AvgBloodPressureChange
         AvgCholestorolChange GlucoseTrend: BloodPressureTrend CholestorolTrend;
RUN;

/*
 * This SAS DATA step demonstrates the FIRST_LAST technique
 * to identify and process the first and last observation
 * within each BY group. Here we're analyzing customer
 * purchase data by account.
 */

/* Create sample data for demonstration */
data customer_transactions;
  input account_id customer_id transaction_date :date9. amount;
  format transaction_date date9.;
  datalines;
  1001 123 01JAN2023 99.99
  1001 123 15JAN2023 49.99
  1001 124 03FEB2023 199.99
  1002 125 10JAN2023 29.99
  1002 125 22JAN2023 79.99
  1003 126 05FEB2023 149.99
  ;
run;

/* Main processing using FIRST_LAST technique */
data account_summary (drop=amount);
  set customer_transactions;

  /* Sort by account_id to prepare for BY processing */
  by account_id;

  /* FIRST_LAST processing::
     - FIRST.account_id identifies first record in each account group
     - LAST.account_id identifies last record in each account group
  */

  /* Initialize variables that will hold our results */
  retain first_purchase_date first_purchase_amount
         last_purchase_date last_purchase_amount
         number_transactions total_spend ;

  /* Initialize values for new group */
  if FIRST.account_id then do;
    first_purchase_date = transaction_date;
    last_purchase_date = transaction_date;
    first_purchase_amount = amount;
    last_purchase_amount = amount;
    number_transactions = 1;
    total_spend = amount;
  end;

  /* For non-first records, accumulate values */
  else do;
    last_purchase_date = transaction_date;
    last_purchase_amount = amount;
    number_transactions + 1;
    total_spend + amount;
  end;

  /* On LAST.record, output the summary */
  if LAST.account_id then do;
    output;
  end;

  /* Keep variables for our output */
  keep account_id customer_id first_purchase_date
       first_purchase_amount last_purchase_date
       last_purchase_amount number_transactions
       total_spend;
run;

/* This DATA step demonstrates the FIRST_LAST pattern in SAS. */
/* It processes customer orders data grouped by customer_id */
/* and creates summary records for first and last order dates. */

DATA work.customer_orders_summary;

  /* Sort input data by customer_id and order_date */
  SET work.customer_orders(WHERE=(order_status='COMPLETED'));

  /* Define BY group processing */
  BY customer_id order_date;  

  /* Determine customers with multiple orders */
  RETAIN first_order_date last_order_date customer_total_quantity customer_total_spend;

  /* Initialize variables when a new customer group starts */
  IF FIRST.customer_id THEN DO;
    first_order_date = .;
    last_order_date = .;
    customer_total_quantity = 0;
    customer_total_spend = 0;
  END;

  /*Capture first and last order dates*/
  IF FIRST.customer_id THEN first_order_date = order_date;
  IF LAST.customer_id THEN last_order_date = order_date;

  /* Accumulate order quantities and spending */
  customer_total_quantity + order_quantity;
  customer_total_spend + order_amount;

  /* Only output a summary record when last observation of the BY group */
  IF LAST.customer_id THEN DO;
    /* Calculate customer statistics */
    avg_order_value = customer_total_spend/customer_total_quantity;
    months_active = INTCK('MONTH', first_order_date, last_order_date) + 1;

    /* Format output record */
    output_length = customer_total_quantity;
    output_value = customer_total_spend;

    /* Deploy dataset */
    OUTPUT;
  END;

  /* Reset accumulated values */
  IF LAST.customer_id THEN DO;
    CALL MISSING(first_order_date, last_order_date, 
                    customer_total_quantity, customer_total_spend);
  END;

/* Add appropriate format to data */
  FORMAT first_order_date last_order_date DATE9.;

RUN;

data patient_visits_summary;
  set patient_visits;
  by patient_id visit_date;

  /* Initialize flags */
  retain first_patient_id last_patient_id first_visit_date last_visit_date;

  /* Flag first and last record in each BY group */
  if first.patient_id then do;
    first_patient_id = 1;
    first_visit_date = visit_date;
  end;
  else do;
    first_patient_id = 0;
    first_visit_date = .;
  end;

  if last.patient_id then do;
    last_patient_id = 1;
    last_visit_date = visit_date;
  end;
  else do;
    last_patient_id = 0;
    last_visit_date = .;
  end;

  /* Calculate time between first and last visit (assuming sorted by visit_date) */
  if last.patient_id then do;
    days_between_visits = last_visit_date - first_visit_date;
    output;
