/* Main macro to control the analysis flow */
%macro analyze_sales_data(start_date, end_date);
    /* Check if the dates provided are valid */
    %if %sysfunc(validate_date(&start_date)) eq 0 or %sysfunc(validate_date(&end_date)) eq 0 %then %do;
        %put ERROR: Invalid date provided. Please check and retry.;
        %return;
    %end;

    /* Calculate the total number of months in the date range */
    %let months_count = %sysevalf(%sysfunc(intck(month,%sysfunc(inputn(&start_date,anydtdte.))+%sysfunc(inputn(&end_date,anydtdte.)))));

    /* Call the macro to prepare the data */
    %prepare_data(&start_date, &end_date, months_count=&months_count);

    /* Determine the threshold for high sales based on the total number of months */
    %let high_sales_threshold = %sysevalf(1000 * &months_count);

    /* Call the macro to summarize the data */
    %summarize_sales(high_sales_threshold=&high_sales_threshold);
%mend analyze_sales_data;

/* Macro to prepare the sales data by filtering based on date */
%macro prepare_data(start_date, end_date, months_count);
    /* Convert the string dates to SAS date values */
    %let start_date_val = %sysfunc(inputn(&start_date,anydtdte.));
    %let end_date_val = %sysfunc(inputn(&end_date,anydtdte.));

    /* Ensure the start date is less than the end date */
    %if &start_date_val > &end_date_val %then %do;
        %put ERROR: Start date should be less than end date.;
        %return;
    %end;

    /* Filter the sales data based on the date range */
    data filtered_sales;
        set company_sales;
        where sale_date between &start_date_val and &end_date_val;
    run;

    /* Log message with the number of months being analyzed */
    %put NOTE: Analyzing sales data over a &months_count-month period.;
%mend prepare_data;

/* Macro to summarize the sales data based on thresholds */
%macro summarize_sales(high_sales_threshold);
    /* Calculate the total sales */
    proc sql;
        create table total_sales as
        select sum(amount) as total_amount
        from filtered_sales;
    quit;

    /* Retrieve the total sales value */
    data _null_;
        set total_sales;
        call symputx('total_amount', total_amount);
    run;

    /* Check if total sales exceed the high sales threshold */
    %if &total_amount > &high_sales_threshold %then %do;
        %put NOTE: High sales detected.;

        /* Call macro to analyze high sales period */
        %analyze_high_sales;
    %end;
    %else %do;
        %put NOTE: Regular sales detected.;

        /* Call macro to analyze regular sales period */
        %analyze_regular_sales;
    %end;
%mend summarize_sales;

