    /* Generate summary statistics for high sales period */
    proc means data=filtered_sales mean std median;
        var amount;
        title 'Summary statistics for high sales period';
    run;

    /* Produce visualization for high sales period */
    proc sgplot data=filtered_sales;
        vbar product / response=amount;
        title 'Sales by product during high sales period';
    run;

%mend analyze_high_sales;

