/*
 * SAS PROC SORT Example: HIGH Complexity
 * Purpose: Sort and deduplicate a sales transactions dataset
 *          while maintaining data integrity and handling special cases
 *
 * Individual Steps:
 * 1. Sort transactions by customer_id ascending, then by transaction_date descending
 * 2. Remove duplicate transactions based on a composite key
 * 3. Subset data to retain only unique products per customer
 */

/* Set system options */
options fullstimer mprint mlogic symbolgen;

/* Sort the sales transactions by customer_id ascending, and by transaction_date descending */
proc sort data=work.raw_sales_transactions out=work.sorted_transactions;
  by customer_id ascending transaction_date descending;
  /* Add where clause to filter out invalid transactions */
  where transaction_date >= '01jan2020'd and amount > 0;
run;

/* Apply NODUPKEY to ensure only unique transactions based on composite key */
proc sort data=work.sorted_transactions
         out=work.unique_transactions(where=(transaction_status='COMPLETED'))
         nodupkey;
  by customer_id transaction_date transaction_id transaction_type amount;
  /* Add an ID statement to log duplicates to a separate dataset */
  id transaction_id product_code;
run;

/* Additional sort to handle a special case for high-value customers */
proc sort data=work.unique_transactions out=work.final_sorted_transactions;
  /* For VIP customers, sort by weighted amount */
  where customer_segment ^= 'VIP';
  by customer_id descending weighted_amount;
run;

/* Extracing unique products for VIP customers */
proc sort data=work.unique_transactions
         out=work.unique_vipProducts(where=(customer_segment='VIP'))
         nodup;
  by customer_id product_code;
run;

/* Merge uniq transactions and vip products to get the final dataset */
proc sort data=work.final_sorted_transactions;
  by customer_id;
run;

proc sort data=work.unique_vipProducts;
  by customer_id;
run;

data work.final_dataset;
  merge work.final_sorted_transactions(in=a)
        work.unique_vipProducts(in=b);
  by customer_id;

  /* Filters */
  if customer_segment='VIP';

  if a and not b then output;
  else if a and b then do;
    if product_code_b ~= product_code_a then output;
  end;
run;

