/*
This SAS code handles missing values in a healthcare dataset.
It primarily focuses on identifying records with missing values
and categorizing them based on the number of missing values.
*/

/* Create a sample dataset with healthcare information */
data healthcare; 
input patient_id gender $ age height weight cholesterol $ glucose bmi; 
datalines;
1 M 45 72 180 228 88 24.6
2 F 38 65 130 . 95 21.6 
3 M 52 70 180 260 110 .
4 F 30 68 140 198 84 21.2
5 M 48 70 . 200 230 86 28.7
6 F 33 . 67 150 200 90 23.4
; 
run;

/* Count and identify missing values */
data healthcare_missing; 
/* Count the missing values for each record */
  nmiss_values = nmiss(of _all_); 
  /* Create a binary flag for records with any missing values */
  any_missing = nmiss_values > 0; 

  /* Categorize records based on the number of missing values */
  if nmiss_values = 0 then missing_category = 'NO_MISSING'; 
  else if nmiss_values >= 1 and nmiss_values <= 2 then missing_category = 'FEW_MISSING'; 
  else if nmiss_values > 2 then missing_category = 'MANY_MISSING';

  /* Specific missing value comparison for cholesterol */
  if cholesterol = ' ' or cholesterol = . or cholesterol = 'MI' then cholesterol_missing = 1; 
  else cholesterol_missing = 0;

  /* Count missing values for specific variables */
  cmiss_numerical = cmiss(of age, height, weight, glucose, bmi);
  cmiss_character = cmiss(of gender, cholesterol);

  set healthcare;
run;

