/* Handling missing values for customer transaction dataset */
data work.transactions_clean;
  set work.transactions_raw;

  /* Create flags for missing values */
  if missing(transaction_amount) then missing_amount_flag = 1;
  else missing_amount_flag = 0;

  /* Using NMISS and CMISS functions */
  num_missing = nmiss(of transaction_date transaction_amount product_id);
  char_missing = cmiss(of customer_name product_category payment_method);

  /* Count missing values by customer */
  if first.customer_id then do;
    missing_value_count = 0;
    valid_transaction_count = 0;
  end;

  /* Categorize missing values */
  if missing(transaction_amount) then do;
    missing_value_count + 1;
    amount_missing_type = 'NA - Mising';
  end;
  else if transaction_amount = . then do;
    missing_value_count + 1;
    amount_missing_type = 'Special Missing';
  end;
  else do;
    valid_transaction_count + 1;
    amount_missing_type = 'Valid Value';
  end;

  /* Imputing missing values */
  if missing(transaction_amount) and not missing(product_id) then do;
    imputed_amount = product_avg_amount[product_id]; /* Assuming product_avg_amount is an array */
  end;

  /* Create quality metrics */
  completeness_score = 1 - (num_missing / (num_missing + (7 - num_missing))); /* 7 = total fields checked */
  valid_trans_pct = valid_transaction_count / (missing_value_count + valid_transaction_count);

  /* MISSING_VALUE_COMPARISON pattern: Comparing missing value reliability */
  length missing_value_reliability $ 20;
  if num_missing > 3 and missing_value_count > valid_transaction_count then do;
    missing_value_reliability = 'Unreliable Record';
    output work.flagged_transactions;
  end;
  else if num_missing <= 2 and valid_trans_pct >= 0.75 then do;
    missing_value_reliability = 'Reliable Record';
    output work.clean_transactions;
  end;
  else do;
    missing_value_reliability = 'Moderate Reliability';
  end;

  /* Retain customer-level values */
  if last.customer_id then do;
    output;
    call missing(of num_missing char_missing amount_missing_type);
  end;

  /* Keep only essential variables */
  keep customer_id transaction_id transaction_date imputed_amount: missing_value_reliability
       completeness_score valid_trans_pct product_id customer_name;
run;

