/*
Calculate monthly and YTD sales totals including tracking monthly trends.
Perform date verification and retain calculations for running totals and YTD values.
*/

DATA sales_trends;
    SET monthly_sales(WHERE=(transaction_date BETWEEN '01JAN2022'D AND '31DEC2022'D));
    BY customer_id transaction_date; /* Required for ROWSFIRST and lag patterns */

    /* Date verification */
    IF _N_ = 1 THEN DO;
        CALL SYMPUTX('START_DATE', PUT(transaction_date, DATE9.), 'G');
    END;
    IF transaction_date LT &START_DATE THEN DO;
        PUT 'ERROR: Transaction date ' transaction_date ' before start date ' &START_DATE; 
        DELETE;
    END;

    /* RETAIN pattern for monthly and YTD calculations */
    RETAIN month_to_date month_total year_to_date monthly_trend last_month_sales;

    /* Initialize variables at start of each year */
    IF FIRST.customer_id THEN DO;
        year_to_date = 0;
        monthly_trend = .;
        last_month_sales = 0;
    END;

    /* Initialize/use variables at start of each month */
    IF FIRST.transaction_date THEN DO;
        month_to_date = 0;
        last_month_sales = month_total;
    END;

    /* Field validation check for amount */
    IF sales_amount LE 0 THEN DO;
       PUT 'Invalid sales amount detected for ' customer_id;
       DELETE;
    END;

    /* Calculate monthly and year-to-date running totals using RETAIN */
    month_to_date + sales_amount;
    month_total = month_to_date;
    year_to_date + sales_amount;

    /* Calculation for 1-month rolling trend using lag (preserved via RETAIN) */
    IF NOT FIRST.transaction_date THEN DO;
        monthly_trend = (month_total - last_month_sales) / last_month_sales;
    END;

    /* Output results */
    IF LAST.transaction_date THEN DO;
        trend_status = IFN(monthly_trend > 0, 'POSITIVE',
                          IFN(monthly_trend < 0, 'NEGATIVE', 'FLAT'));
        OUTPUT;
    END;

    /* Clean variables */
   DROP month_to_date;
    RETAIN month_total year_to_date monthly_trend last_month_sales;

    /*μένες ποιοτικές ετικέτες μηνιαίας τάσης */
    FORMAT monthly_trend percent8.2;
    LABEL year_to_date = 'Year-to-Date Sales';
    LABEL month_total = 'Monthly Sales Total';
    LABEL monthly_trend = 'Monthly Trend vs Previous';
RUN;

/* This SAS code calculates the running total and moving average of sales per customer */
data customer_sales_analysis;
    set transactions;

    /* Initialize retain variables */
    retain customer_id prev_customer_id running_total moving_average lag_sales;

    /* Reset running total and moving average when customer_id changes */
    if customer_id ^= prev_customer_id then do;
        running_total = 0;
        moving_average = 0;
        lag_sales = 0;
    end;

    /* Calculate running total */
    running_total + sale_amount;

    /* Calculate lag sales */
    if first.customer_id then do;
        lag_sales = sale_amount;
    end;
    else do;
        lag_sales = lag(sale_amount);
    end;

    /* Calculate moving average */
    if first.customer_id then do;
        moving_average = sale_amount;
    end;
    else do;
        moving_average = (moving_average * (count - 1) + sale_amount) / count;
    end;

    /* Keep track of previous customer_id */
    prev_customer_id = customer_id;

    /* Output variables */
    retain customer_id prev_customer_id running_total moving_average lag_sales;
run;

