* Author: Genius Expert
* Purpose: Calculate running totals for daily sales by product and detect lag patterns
* Category: DATA_STEP_RETAIN
* Complexity: HIGH
* Date: 2023-11-15
*/

/* Read in daily sales data */
data sales_trends;
  set daily_sales(lower_bound_sales_date='01JAN2023'd); 

  /* Initialize running total counters and flags using RETAIN */
  retain product_flag prior_day_sales prior_product; 
  retain monthly_single_cust_sales_cnt monthly_multi_cust_sales_cnt 0;  
  retain prior_month_product_sales 0;   

  /* Tracking overarching state */
  if first.product_id then do;
     monthly_single_cust_sales_cnt=0;
     monthly_multi_cust_sales_cnt=0;
     prior_month_product_sales=0;
  end; 

  /* Set initial lag values for new product series processing */
  if _N_=1 then do; 
     product_flag=0;
     prior_day_sales=0;
     prior_product='_;
  end;

  /* Calculate cumulative sales metrics */
  monthly_all_sales_cnt + 1;

  if customer_id=new_customer_id then do;
     monthly_single_cust_sales_cnt + 1;
  end; 
  else do;
     monthly_multi_cust_sales_cnt + 1;
  end;   

  /* Detect if lag pattern exists by comparing to prior day/same product */
  if product_id=prior_product then do;
     if sales_amount < prior_day_sales then lag_pattern_flag=1;
     else lag_pattern_flag=0;  
  end;   

  /* Update tracking variables using conditional retain logic */
  prior_day_sales = sales_amount;
  prior_product = product_id;
  new_customer_id = customer_id;

  /* Calculate prior month sales totals to incorporate seasonal trends */
  if intnx('month',sales_date,0)=intnx('month',today(),-1) then do;
     prior_month_product_sales + sales_amount;
  end;

  /* Format outputs and metrics */
  format sales_date yymmdd10. sales_amount dollar12.2;
  product_sales_ratio = divide(monthly_multi_cust_sales_cnt, monthly_single_cust_sales_cnt, 0);
  format product_sales_ratio percent8.1;

  /* Output results */
  keep product_id customer_id sales_date sales_amount
      monthly_single_cust_sales_cnt monthly_multi_cust_sales_cnt
      lag_pattern_flag prior_month_product_sales product_sales_ratio;

  /* Output status */
  put 'NOTE: Running totals and lag comparison complete for ' product_id=;

run;

