  1005 15JAN2023 210.00 Electronics Active
  1004 18JAN2023 65.00 Groceries Active
  1003 20JAN2023 180.00 Furniture Active
;
run;

/* Sort data by customer_id and transaction_date */
proc sort data=transactions;
  by customer_id transaction_date;
run;

/* Process data with RETAIN to calculate running totals and detect status changes */
data customer_activity (drop=prev_status prev_amount);
  set transactions;
  by customer_id;

  /* Initialize variables that need to be retained across observations */
  retain running_total lag_amount prev_status prev_amount status_change_count status_history;

  /* Initialize variables for each new customer */
  if first.customer_id then do;
    running_total = 0;
    lag_amount = .;
    prev_status = ' ';
    prev_amount = .;
    status_change_count = 0;
    status_history = ' ';
  end;

  /* Calculate running total of amounts */
  running_total + amount;

  /* Create lag variable for amount */
  if not first.customer_id then do;
    lag_amount = lag(amount);
  end;

  /* Track status changes */
  if first.customer_id then do;
    status_history = status;
  end;
  else do;
    if status ne prev_status then do;
      status_change_count + 1;
      status_history = catx('->', status_history, status);
    end;
  end;

  /* Update previous values for next iteration */
  prev_status = status;
  prev_amount = amount;

  /* Calculate time between transactions */
  if not first.customer_id then do;
    days_since_last_purchase = transaction_date - lag(transaction_date);
  end;
  else do;
    days_since_last_purchase = .;
  end;

  /* Classify customers based on purchasing pattern */
  if running_total > 500 then customer_segment = 'High Value';
  else if running_total > 200 then customer_segment = 'Medium Value';
  else customer_segment = 'Low Value';

  /* Calculate moving average of last 3 transactions */
  retain transaction_count1-transition_count3 transaction_sum1-transition_sum3;

  if first.customer_id then do;
    transaction_count1 = 0;
    transaction_sum1 = 0;
    transaction_count2 = 0;
    transaction_sum2 = 0;
    transaction_count3 = 0;
    transaction_sum3 = 0;
  end;

  /* Update rolling counts and sums */
  if transaction_count3 > 0 then do;
    transaction_count3 = transaction_count2;
    transaction_sum3 = transaction_sum2;
  end;

  if transaction_count2 > 0 then do;
    transaction_count2 = transaction_count1;
    transaction_sum2 = transaction_sum1;
  end;

  transaction_count1 = 1;
  transaction_sum1 = amount;

  /* Calculate moving averages */
  if transaction_count1 = 3 then do;
    moving_avg_3trans = transaction_sum1 / 3;
  end;
  else if transaction_count2 = 3 then do;
    moving_avg_3trans = transaction_sum2 / 3;
  end;
  else if transaction_count3 = 3 then do;
    moving_avg_3trans = transaction_sum3 / 3;
  end;
  else do;
    moving_avg_3trans = .;
  end;

  /* Keep track of purchase categories */
  retain purchase_categories;
  if first.customer_id then purchase_categories = ' ';
  if first.purchase_category then do;
    if find(purchase_categories, purchase_category, ' ') = 0 then do;
      purchase_categories = catx(' ', purchase_categories, purchase_category);
    end;
  end;
run;

/* Output sample of processed data */
proc print data=customer_activity (obs=10);
  title "Customer Activity with Running Totals and Status Changes";
run;

/* Calculate customer running totals and lag patterns for sales data */
data work.customer_sales_analysis;
  /* Declare input dataset with customer sales records */
  set work.raw_customer_sales;

  /* Use RETAIN to hold cumulative values across iterations */
  retain cust_running_total 0;
  retain prev_month_sales 0;
  retain curr_month_sales 0;

  /* Calculate monthly running total of sales per customer */
  by customer_id transaction_month;

  /* Reset running total for each new customer */
  if first.customer_id then do;
    cust_running_total = 0;
    prev_month_sales = 0;
  end;

  /* Calculate current month's sales and running total */
  curr_month_sales = sum(amount);
  cust_running_total + curr_month_sales;

  /* Track lag values for trend analysis */
  if not first.transaction_month then do;
    lag_1_month = prev_month_sales;
    lag_2_month = lag(prev_month_sales);
  end;

  /* Calculate month-over-month growth */
  if not first.transaction_month and prev_month_sales > 0 then do;
    mom_growth_pct = ((curr_month_sales - prev_month_sales) / prev_month_sales) * 100;
  end;

  /* Store values for next iteration */
  prev_month_sales = curr_month_sales;

  /* Create identifier for running total records */
  if last.customer_id then do;
    running_total_flag = 1;
    output;
  end;
  else do;
    running_total_flag = 0;
    output;
  end;

  /* Calculate quarterly running totals */
  retain qtr_running_total 0;
  retain qtr_prev_total 0;

  if first.qtr then do;
    qtr_running_total = 0;
    qtr_prev_total = 0;
  end;

  qtr_running_total + curr_month_sales;

  if last.qtr then do;
    qtr_growth_pct = ((qtr_running_total - qtr_prev_total) / qtr_prev_total) * 100;
    qtr_prev_total = qtr_running_total;
  end;

  /* Format output variables */
  format cust_running_total qtr_running_total dollar12.2;
  format mom_growth_pct qtr_growth_pct percent8.2;
  format transaction_month monyy7.;

  /* Label variables for clarity */
  label cust_running_total = 'Cumulative Customer Sales';
  label qtr_running_total = 'Quarterly Running Total';
  label mom_growth_pct = 'Month-over-Month Growth %';
  label qtr_growth_pct = 'Quarter-over-Quarter Growth %';
  label lag_1_month = 'Lag 1 Month Sales';
  label lag_2_month = 'Lag 2 Month Sales';

  /* Keep only necessary variables in output */
  keep customer_id transaction_month amount
       cust_running_total qtr_running_total
       mom_growth_pct qtr_growth_pct
       lag_1_month lag_2_month running_total_flag;

  /* Sort output by customer and date */
  proc sort data=work.customer_sales_analysis;
    by customer_id transaction_month;
  run;

data premiums_policy_summ;
  /* Sample SAS program using RETAIN to calculate running totals and identifying lag patterns */
  /* in insurance policy premiums dataset. RETAIN crucial for correctly building sequential */
  /* running-totals that persist across observations, and for lag calcs*/

  retain running_total_standard_premiums running_total_optpremiums  
         cur_policy_count_standard cur_policy_count_opt  
         prev_year_premiums_standard prev_year_premiums_opt ;

  set work.policy_analytic_dmart;

  /* Initialize retained values at start of each new policy date*/
  if first.policy_year then do;
    running_total_standard_premiums = 0;
    running_total_optpremiums = 0;
    cur_policy_count_standard = 0;
    cur_policy_count_opt = 0;
    prev_year_premiums_standard = lag1(total_premiums_standard);
    prev_year_premiums_opt = lag1(total_premiums_opt);
  end;

  /* Calculate previous year lag variables using retain */
  retain prev_year_premiums_standard prev_year_premiums_opt ;

  /* running totals using retain */
  running_total_standard_premiums + standard_premium ;
  running_total_optpremiums + optional_coverage_premiums ;

  /* Count premium policies with retain */
  if standard_premium > 0 then cur_policy_count_standard + 1 ;

  /* Track optional premiums */
  if optional_coverage_premiums > 0 then do;
    cur_policy_count_opt + 1 ;
    opt_pct = (optional_coverage_premiums/running_total_optpremiums)*100;
  end;

  /* Compare to lagged previous year premium */
  if total_premiums_standard > prev_year_premiums_standard then 
      premium_increase_flag_standard = 1;

  /* carry forward running totals, current counts, lag vars */
  retain running_total_standard_premiums running_total_optpremiums 
         cur_policy_count_standard cur_policy_count_opt  
         prev_year_premiums_standard prev_year_premiums_opt ;

  /* Output results */
  output premieres_program_summary;   
run;

/* Full example including summary reporting */
proc report data=premieres_program_summary nowd;
  column policy_year customer_region running_total_standard_premiums running_total_optpremiums
         premium_increase_flag_standard cur_policy_count_standard opt_pct;

  define policy_year / group;
  define customer_region / group;
  define premium_increase_flag_standard / display 'Standard Premium Increase Flag' format=yesno.;

  rbreak after / summarize;
run;

/*
This SAS DATA step demonstrates the use of RETAIN to calculate
running totals and detect lag patterns in customer transaction data
*/
data work.customer_analysis;
  set sashelp.retail;

  /* Initialize retained variables for running totals and lag detection */
  retain cumulative_spend lag_spend transaction_count 0;
  retain prev_customer_id prev_spend prev_date;
  retain consecutive_purchase_flag 0;

  /* Calculate running total of spend by customer */
  if _n_ = 1 then do;
    cumulative_spend = 0;
    transaction_count = 0;
  end;

  /* Detect change in customer ID */
  if customer_id ne prev_customer_id then do;
    consecutive_purchase_flag = 0;
  end;
  else if date_part(transaction_date) = prev_date then do;
    consecutive_purchase_flag + 1;
  end;

  /* Update running totals when customer ID hasn't changed */
  if customer_id eq prev_customer_id then do;
    cumulative_spend = sum(cumulative_spend, product_price * quantity);
    transaction_count + 1;
  end;
  /* Else reset running totals for new customer */
  else do;
    cumulative_spend = product_price * quantity;
    transaction_count = 1;
  end;

  /* Calculate lag spend (previous purchase amount) */
  lag_spend = lag(product_price * quantity);

  /* Create a large spend increase flag */
  if _n_ > 1 and customer_id = prev_customer_id and 
     (product_price * quantity) > (lag_spend * 2) then 
     large_spend_increase_flag = 1;
  else large_spend_increase_flag = 0;

  /* Store current values for next iteration */
  prev_customer_id = customer_id;
  prev_spend = product_price * quantity;
  prev_date = date_part(transaction_date);

  /* Create summary metrics */
  avg_spend = cumulative_spend / transaction_count;

  /* Logging for debugging */
  putlog 'Processing customer: ' customer_id= 'Cumulative spend: ' cumulative_spend=;

  /* Keep important variables */
  keep customer_id transaction_date product_name product_price quantity
       cumulative_spend transaction_count avg_spend lag_spend
       consecutive_purchase_flag large_spend_increase_flag;
run;
